const data = $input.item.json;

const contentGaps = data.top_content_gaps || [];
const decayingPages = data.decaying_pages || [];
const quickWins = data.quick_win_rankings || [];
const openOpps = data.open_opportunities || [];

const prompt = `You are an SEO strategist for a digital marketing agency. Here is this week's SEO data across 3 client sites:

TOP CONTENT GAPS (by priority score):
${JSON.stringify(contentGaps, null, 2)}

DECAYING PAGES (dropped 5+ positions in 90 days):
${JSON.stringify(decayingPages, null, 2)}

QUICK WIN RANKINGS (positions 6-10, needs a push to top 5):
${JSON.stringify(quickWins, null, 2)}

OPEN OPPORTUNITIES:
${JSON.stringify(openOpps, null, 2)}

Generate a prioritised action list of EXACTLY 5 items ranked by expected traffic impact.

For each action include:
- what_to_do: specific action (1 sentence)
- why: data-based reason (1 sentence)  
- expected_result: what improvement to expect
- time_to_implement: "30 min" / "2 hours" / "1 day"
- client: which client this is for

Return ONLY valid JSON:
{
  "week_summary": "one sentence summary of this week",
  "actions": [
    {"rank": 1, "what_to_do": "...", "why": "...", "expected_result": "...", "time_to_implement": "...", "client": "..."}
  ]
}`;

return [{ json: { prompt, rawData: data } }];

const claudeData = $input.item.json;

let digest = { week_summary: '', actions: [] };
try {
  const rawText = claudeData.content?.[0]?.text || '{}';
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  digest = jsonMatch ? JSON.parse(jsonMatch[0]) : digest;
} catch(e) {
  digest.week_summary = 'Unable to generate AI summary this week';
}

// Format for Slack
let msg = `*🎯 SEO Weekly Opportunity Digest — ${new Date().toDateString()}*\n`;
msg += `_${digest.week_summary}_\n\n`;
msg += `*Top 5 Actions This Week:*\n`;

(digest.actions || []).forEach((action, i) => {
  const emoji = i === 0 ? '🔥' : i === 1 ? '⭐' : i === 2 ? '✅' : '📋';
  msg += `\n${emoji} *${i+1}. ${action.what_to_do}*`;
  msg += `\n   Client: ${action.client} | Time: ${action.time_to_implement}`;
  msg += `\n   Why: ${action.why}`;
  msg += `\n   Expected: ${action.expected_result}`;
});

msg += `\n\n_Generated by Growth Escalators SEO Automation_`;

return [{ json: { slackMessage: msg } }];
